// This is a simple interface which specifies echo.Route addition functions which
// are present on both echo.Echo and echo.Group, since we want to allow using
// either of them for path registration
type EchoRouter interface {
	CONNECT(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	DELETE(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	GET(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	HEAD(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	OPTIONS(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	PATCH(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	POST(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	PUT(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	TRACE(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
}

// RegisterHandlers adds each server route to the EchoRouter.
func RegisterHandlers(router EchoRouter, si ServerInterface) {
	RegisterHandlersWithBaseURL(router, si, "")
}

// Registers handlers, and prepends BaseURL to the paths, so that the paths
// can be served under a prefix.
func RegisterHandlersWithBaseURL(router EchoRouter, si ServerInterface, baseURL string) {

	wrapper := ServerInterfaceWrapper{
		Handler: si,
	}

	router.GET(baseURL+"/audit-logs", wrapper.ListAuditLogs)
	router.POST(baseURL+"/auth/change-password", wrapper.ChangePassword)
	router.POST(baseURL+"/auth/login", wrapper.Login)
	router.POST(baseURL+"/auth/logout", wrapper.Logout)
	router.GET(baseURL+"/auth/me", wrapper.GetCurrentUser)
	router.POST(baseURL+"/auth/resend-code", wrapper.ResendCode)
	router.PUT(baseURL+"/auth/update-profile", wrapper.UpdateProfile)
	router.POST(baseURL+"/auth/verify", wrapper.VerifyMFA)
	router.GET(baseURL+"/merchants", wrapper.ListMerchants)
	router.POST(baseURL+"/merchants/create", wrapper.CreateMerchant)
	router.GET(baseURL+"/merchants/:id", wrapper.GetMerchant)
	router.DELETE(baseURL+"/merchants/:id/delete", wrapper.DeleteMerchant)
	router.PUT(baseURL+"/merchants/:id/update", wrapper.UpdateMerchant)
	router.GET(baseURL+"/payment-providers", wrapper.ListPaymentProviders)
	router.GET(baseURL+"/payouts", wrapper.ListPayouts)
	router.POST(baseURL+"/payouts/create", wrapper.CreatePayout)
	router.GET(baseURL+"/payouts/:id", wrapper.GetPayout)
	router.DELETE(baseURL+"/payouts/:id/delete", wrapper.DeletePayout)
	router.PUT(baseURL+"/payouts/:id/update", wrapper.UpdatePayout)
	router.GET(baseURL+"/permissions", wrapper.ListPermissions)
	router.GET(baseURL+"/roles", wrapper.ListRoles)
	router.POST(baseURL+"/roles/create", wrapper.CreateRole)
	router.GET(baseURL+"/roles/:id", wrapper.GetRole)
	router.DELETE(baseURL+"/roles/:id/delete", wrapper.DeleteRole)
	router.PUT(baseURL+"/roles/:id/update", wrapper.UpdateRole)
	router.GET(baseURL+"/users", wrapper.ListUsers)
	router.POST(baseURL+"/users/create", wrapper.CreateUser)
	router.GET(baseURL+"/users/:id", wrapper.GetUser)
	router.DELETE(baseURL+"/users/:id/delete", wrapper.DeleteUser)
	router.PUT(baseURL+"/users/:id/update", wrapper.UpdateUser)

}

